mapper.select:
SELECT r.*, u.nickname, u.avatar, b.title AS book_title FROM review r LEFT JOIN user u ON r.user_id = u.id LEFT JOIN book b ON r.book_id = b.id
AND (b.title LIKE CONCAT('%', #{keyword}, '%') OR u.username LIKE CONCAT('%', #{keyword}, '%') OR u.nickname LIKE CONCAT('%', #{keyword}, '%') OR r.content LIKE CONCAT('%', #{keyword}, '%'))
AND r.rating = #{rating}
AND r.book_id = #{bookId}
AND r.user_id = #{userId}
ORDER BY r.create_time DESC
